                                    {t.qrDownloadHighQuality}
                                </button>
                                <p className="text-sm text-text-dark/50 dark:text-text-light/50 mt-4">{t.qrScanHint}</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

