import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useLanguage } from '../../contexts/LanguageContext';
import { translations } from '../../translations/translations';
// @ts-ignore
import QRCodeStyling from 'qr-code-styling';
// @ts-ignore
import html2canvas from 'html2canvas';

interface QrFixProps {
    link?: string;
}

const QrFix: React.FC<QrFixProps> = ({ link }) => {
    const { language } = useLanguage();
    const [qrCode, setQrCode] = useState<QRCodeStyling | null>(null);
    const [qrCodeImage, setQrCodeImage] = useState<string | null>(null);
    const [labelText, setLabelText] = useState<string>('Scan Me!');
    const [frameType, setFrameType] = useState<'polite' | 'phone' | 'bubble'>('polite');
    const [frameColor, setFrameColor] = useState('#222');
    const qrCodeContainerRef = useRef<HTMLDivElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        if (!link) return;

        const qrCodeInstance = new QRCodeStyling({
            width: 200,
            height: 200,
            type: "canvas",
            data: link,
            image: "",
            dotsOptions: {
                color: "#222",
                type: "rounded",
            },
            cornersSquareOptions: {
                color: "#222",
                type: "dot",
            },
            cornersDotOptions: {
                color: "#222",
                type: "dot",
            },
            backgroundOptions: {
                color: "#fff",
            },
            imageOptions: {
                crossOrigin: "anonymous",
                margin: 0,
                imageSize: 0.4,
                hideBackgroundDots: true
            },
        });

        setQrCode(qrCodeInstance);
        qrCodeInstance.append(qrCodeContainerRef.current);

        return () => {
            qrCodeInstance.clear();
        };
    }, [link]);

    useEffect(() => {
        if (!qrCode) return;

        qrCode.update({
            data: link,
            dotsOptions: { color: frameColor },
            cornersSquareOptions: { color: frameColor },
            cornersDotOptions: { color: frameColor },
        });

    }, [link, frameColor, qrCode]);

    useEffect(() => {
        const downloadImage = async () => {
            if (!qrCode || !canvasRef.current) return;
            const canvas = canvasRef.current;
            const context = canvas.getContext('2d');
