}

const AccordionItem: React.FC<AccordionItemProps> = ({ title, icon: Icon, isOpen, onClick, children }) => (
    <div className="border-b border-gray-200 dark:border-gray-700/50 last:border-0">
        <button
            onClick={onClick}
