                </div>
                <span className={`font-bold ${isOpen ? 'text-primary' : 'text-text-dark dark:text-text-light'}`}>{title}</span>
            </div>
            <ChevronDown size={20} className={`transition-transform duration-300 ${isOpen ? 'rotate-180 text-primary' : 'text-gray-400'}`} />
