                                <motion.div 
                                    layout
                                    className="flex flex-wrap justify-center gap-8"
                                >
                                    {baseStations.map(station => (
                                        <motion.div 
                                            key={station.nameKey} 
                                            layout 
                                            initial={{ opacity: 0 }} 
