                                </motion.div>

                                <div className="mt-20">
                                    <MusicVolumeFolder isOpen={isFolderOpen} onClick={() => setIsFolderOpen(!isFolderOpen)} />
                                    <AnimatePresence>
                                        {isFolderOpen && (
                                            <motion.div
                                                key="folder-content"
