    <content><![CDATA[
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mail, Send, CheckCircle, User, MessageSquare, AlertCircle, Phone } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { translations } from '../translations/translations';

export default function Contact() {
  const { language } = useLanguage();
  const t = translations[language];

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    email: '',
    message: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setShowSuccessMessage(false);

    try {
      const response = await fetch('/api/contact', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || t.errorMessage);
      }

      setShowSuccessMessage(true);
      setFormData({ name: '', phone: '', email: '', message: '' });

      // Auto-hide success message after 7 seconds
      setTimeout(() => setShowSuccessMessage(false), 7000);
    } catch (err: any) {
      console.error('Contact Form Error:', err);
      setError(err.message || t.errorMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <main className="flex-1">
      <div className="py-10">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center mb-10"
          >
            <h1 className="text-4xl md:text-5xl font-bold text-text-dark dark:text-text-light mb-4 font-rubik">
              <span className="bg-gradient-to-r from-primary to-secondary bg-clip-text text-transparent">{t.contactTitle}</span>
            </h1>
            <div className="inline-block glass-card p-3 px-6 rounded-2xl border border-white/40 shadow-sm">
                <p className="text-base md:text-lg text-text-dark/70 dark:text-text-light/70 leading-relaxed font-light">{t.contactSubtitle}</p>
            </div>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.7, delay: 0.2 }}
          >
            <div className="glass-card rounded-[2.5rem] border border-white/50 dark:border-white/10 overflow-hidden shadow-2xl">
              <div className="flex flex-col space-y-1 p-6 text-center pb-6 bg-gradient-to-b from-white/20 to-transparent">
                <div className="w-16 h-16 mx-auto mb-3 bg-gradient-to-br from-primary to-secondary rounded-2xl flex items-center justify-center shadow-lg transform rotate-3">
                  <Mail className="w-8 h-8 text-white" />
                </div>
                <h3 className="font-bold tracking-tight text-xl text-text-dark dark:text-text-light font-rubik">{t.contactFormTitle}</h3>
                <p className="text-xs text-text-dark/70 dark:text-text-light/70 font-light">{t.contactFormSubtitle}</p>
              </div>
              <div className="p-8 md:p-12 pt-0">
                <form 
                  onSubmit={handleSubmit} 
                  className="space-y-5"
                >
