        throw new Error(result.error || t.errorMessage || 'שגיאה בשליחה');
      }

      setShowSuccessMessage(true);
      setFormData({ name: '', phone: '', email: '', message: '' });
      setTimeout(() => setShowSuccessMessage(false), 7000);
